230	  cachedRawSettings = raw;
231	  cachedSnapshot = parsePersistedSettings(raw);
232	  return cachedSnapshot;
233	}
234	
235	function persistSettings(next: AppSettings): void {
236	  if (typeof window === "undefined") return;
237	
238	  const raw = JSON.stringify(next);
239	  try {
240	    if (raw !== cachedRawSettings) {
241	      window.localStorage.setItem(APP_SETTINGS_STORAGE_KEY, raw);
242	    }
243	  } catch {
244	    // Best-effort persistence only.
245	  }
246	
247	  cachedRawSettings = raw;
248	  cachedSnapshot = next;
249	}
250	
251	function subscribe(listener: () => void): () => void {
252	  listeners.push(listener);
253	
254	  const onStorage = (event: StorageEvent) => {
255	    if (event.key === APP_SETTINGS_STORAGE_KEY) {
256	      emitChange();
257	    }
258	  };
259	
260	  window.addEventListener("storage", onStorage);
261	  return () => {
262	    listeners = listeners.filter((entry) => entry !== listener);
263	    window.removeEventListener("storage", onStorage);
264	  };
265	}
266	
267	export function useAppSettings() {
268	  const settings = useSyncExternalStore(
269	    subscribe,
270	    getAppSettingsSnapshot,
271	    () => DEFAULT_APP_SETTINGS,
272	  );
273	
274	  const updateSettings = useCallback((patch: Partial<AppSettings>) => {
275	    const next = normalizeAppSettings(
276	      Schema.decodeSync(AppSettingsSchema)({
277	        ...getAppSettingsSnapshot(),
278	        ...patch,
279	      }),
280	    );
281	    persistSettings(next);
282	    emitChange();
283	  }, []);
284	
285	  const resetSettings = useCallback(() => {
286	    persistSettings(DEFAULT_APP_SETTINGS);
287	    emitChange();
288	  }, []);
289	
290	  return {
291	    settings,
292	    updateSettings,
293	    resetSettings,
294	    defaults: DEFAULT_APP_SETTINGS,
295	  } as const;
296	}
