/**
 * Theme definitions shared across server and web.
 *
 * Each theme provides named color tokens for the major UI regions.
 * The `appearance` field tells the renderer whether to apply dark-mode
 * overrides (e.g. the `.dark` class in the web app).
 */

export interface ThemeColorTokens {
  /** Page / canvas background */
  readonly background: string;
  /** Default text color */
  readonly foreground: string;
  /** Primary brand / interactive accent */
  readonly accent: string;
  /** Text rendered on top of the accent color */
  readonly accentForeground: string;
  /** Sidebar panel background */
  readonly sidebar: string;
  /** Sidebar text / icon color */
  readonly sidebarForeground: string;
  /** Editor / main content area background */
  readonly editor: string;
  /** Editor text color */
  readonly editorForeground: string;
  /** Integrated terminal background */
  readonly terminal: string;
  /** Terminal text color */
  readonly terminalForeground: string;
  /** Status bar background */
  readonly statusBar: string;
  /** Status bar text color */
  readonly statusBarForeground: string;
}

export interface ThemeDefinition {
  readonly id: string;
  readonly name: string;
  /** Controls whether the host toggles dark-mode treatment (e.g. `.dark` class). */
  readonly appearance: "light" | "dark";
  readonly colors: ThemeColorTokens;
}

export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

