import { BUILT_IN_THEMES, THEME_IDS, type ThemeDefinition } from "@t3tools/shared/theme";

import { useTheme } from "../hooks/useTheme";

/** Miniature layout preview showing sidebar, editor, terminal and status bar. */
function ThemeSwatch({ theme }: { theme: ThemeDefinition }) {
  const { colors } = theme;
  return (
    <div
      className="flex h-14 w-[5.5rem] shrink-0 flex-col overflow-hidden rounded-md border border-border shadow-xs"
      style={{ background: colors.background }}
      aria-hidden
    >
      {/* Main area: sidebar + editor/terminal stack */}
      <div className="flex min-h-0 flex-1">
        {/* Sidebar */}
        <div className="flex w-5 shrink-0 flex-col items-center gap-[3px] py-1.5" style={{ background: colors.sidebar }}>
          <span className="block h-[3px] w-2 rounded-full" style={{ background: colors.sidebarForeground, opacity: 0.6 }} />
          <span className="block h-[3px] w-2 rounded-full" style={{ background: colors.sidebarForeground, opacity: 0.35 }} />
          <span className="block h-[3px] w-2 rounded-full" style={{ background: colors.sidebarForeground, opacity: 0.35 }} />
        </div>

        {/* Editor + terminal */}
        <div className="flex min-h-0 flex-1 flex-col">
          <div className="flex flex-1 items-start px-1 pt-1.5" style={{ background: colors.editor }}>
            <span className="block h-[3px] w-6 rounded-full" style={{ background: colors.editorForeground, opacity: 0.3 }} />
          </div>
          <div className="flex h-3 shrink-0 items-center px-1" style={{ background: colors.terminal }}>
            <span className="block h-[2px] w-4 rounded-full" style={{ background: colors.terminalForeground, opacity: 0.35 }} />
          </div>
        </div>
      </div>

      {/* Status bar */}
      <div className="flex h-2.5 shrink-0 items-center gap-1 px-1" style={{ background: colors.statusBar }}>
        <span className="block h-[3px] w-2.5 rounded-full" style={{ background: colors.accent }} />
        <span className="block h-[2px] w-3 rounded-full" style={{ background: colors.statusBarForeground, opacity: 0.35 }} />
      </div>
    </div>
  );
}

export function ThemeSelector() {
  const { colorTheme, setColorTheme } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {THEME_IDS.map((id) => {
        const theme = BUILT_IN_THEMES[id];
        const selected = colorTheme === id;
        return (
          <button
            key={id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setColorTheme(id)}
          >
            <ThemeSwatch theme={theme} />

            <span className="flex min-w-0 flex-col">
              <span className="text-sm font-medium">{theme.name}</span>
              <span className="text-xs capitalize">{theme.appearance} theme</span>
            </span>

            {selected ? (
              <span className="ml-auto shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

