import { type ReactNode, createElement, useCallback, useEffect, useSyncExternalStore } from "react";
import {
  BUILT_IN_THEMES,
  isThemeId,
  type ThemeColorTokens,
  type ThemeDefinition,
  type ThemeId,
} from "@t3tools/shared/theme";

type Mode = "light" | "dark" | "system";

interface ThemeSnapshot {
  mode: Mode;
  systemDark: boolean;
  colorTheme: ThemeId;
}

const MODE_STORAGE_KEY = "t3code:theme";
const COLOR_THEME_STORAGE_KEY = "t3code:color-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";
const DEFAULT_COLOR_THEME: ThemeId = "t3-dark";

// ---------------------------------------------------------------------------
// Camel-case token key  →  CSS custom property name
// ---------------------------------------------------------------------------
const TOKEN_TO_CSS_PROPERTY: Record<keyof ThemeColorTokens, string> = {
  background: "--t3-background",
  foreground: "--t3-foreground",
  accent: "--t3-accent",
  accentForeground: "--t3-accent-foreground",
  sidebar: "--t3-sidebar",
  sidebarForeground: "--t3-sidebar-foreground",
  editor: "--t3-editor",
  editorForeground: "--t3-editor-foreground",
  terminal: "--t3-terminal",
  terminalForeground: "--t3-terminal-foreground",
  statusBar: "--t3-status-bar",
  statusBarForeground: "--t3-status-bar-foreground",
};

// ---------------------------------------------------------------------------
// External store plumbing
// ---------------------------------------------------------------------------
let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredMode(): Mode {
  const raw = localStorage.getItem(MODE_STORAGE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredColorTheme(): ThemeId {
  const raw = localStorage.getItem(COLOR_THEME_STORAGE_KEY);
  if (raw !== null && isThemeId(raw)) return raw;
  return DEFAULT_COLOR_THEME;
}

// ---------------------------------------------------------------------------
// DOM side-effects
// ---------------------------------------------------------------------------
function applyMode(mode: Mode, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const isDark = mode === "dark" || (mode === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

function applyColorTheme(themeId: ThemeId) {
  const theme = BUILT_IN_THEMES[themeId];
  const style = document.documentElement.style;
  const tokens = theme.colors;

  for (const key of Object.keys(TOKEN_TO_CSS_PROPERTY) as Array<keyof ThemeColorTokens>) {
    style.setProperty(TOKEN_TO_CSS_PROPERTY[key], tokens[key]);
  }
}

// Apply both immediately on module load to prevent flash
applyMode(getStoredMode());
applyColorTheme(getStoredColorTheme());

// ---------------------------------------------------------------------------
// Snapshot
// ---------------------------------------------------------------------------
function getSnapshot(): ThemeSnapshot {
  const mode = getStoredMode();
  const systemDark = mode === "system" ? getSystemDark() : false;
  const colorTheme = getStoredColorTheme();

  if (
    lastSnapshot &&
    lastSnapshot.mode === mode &&
    lastSnapshot.systemDark === systemDark &&
    lastSnapshot.colorTheme === colorTheme
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { mode, systemDark, colorTheme };
  return lastSnapshot;
}

// ---------------------------------------------------------------------------
// Subscribe
// ---------------------------------------------------------------------------
function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStoredMode() === "system") applyMode("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === MODE_STORAGE_KEY) {
      applyMode(getStoredMode(), true);
      emitChange();
    }
    if (e.key === COLOR_THEME_STORAGE_KEY) {
      applyColorTheme(getStoredColorTheme());
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------
export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const mode = snapshot.mode;
  const colorTheme = snapshot.colorTheme;

  const resolvedTheme: "light" | "dark" =
    mode === "system" ? (snapshot.systemDark ? "dark" : "light") : mode;

  const setTheme = useCallback((next: Mode) => {
    localStorage.setItem(MODE_STORAGE_KEY, next);
    applyMode(next, true);
    emitChange();
  }, []);

  const setColorTheme = useCallback((next: ThemeId) => {
    localStorage.setItem(COLOR_THEME_STORAGE_KEY, next);
    applyColorTheme(next);
    emitChange();
  }, []);

  const themeDefinition: ThemeDefinition = BUILT_IN_THEMES[colorTheme];

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyMode(mode);
  }, [mode]);

  useEffect(() => {
    applyColorTheme(colorTheme);
  }, [colorTheme]);

  return {
    /** Current mode preference (light / dark / system) */
    theme: mode,
    setTheme,
    /** The effective light or dark appearance after resolving "system" */
    resolvedTheme,
    /** Currently active color theme id */
    colorTheme,
    setColorTheme,
    /** Full definition for the active color theme */
    themeDefinition,
  } as const;
}

// ---------------------------------------------------------------------------
// Provider — thin wrapper that ensures theme effects run at the tree root.
// ---------------------------------------------------------------------------
export function ThemeProvider({ children }: { children: ReactNode }) {
  // Calling the hook here guarantees the useEffect subscriptions are active
  // at the top of the component tree, keeping the DOM in sync.
  useTheme();
  return createElement("div", { "data-theme-provider": "" }, children);
}
